import json, os
from dataclasses import dataclass
@dataclass
class Config:
    port: int = 8080
    debug: bool = False
    @classmethod
    def load(cls, path='config.json'):
        data = json.loads(open(path).read()) if os.path.exists(path) else {}
        return cls(**{k: v for k, v in data.items() if hasattr(cls, k)})

import logging
def setup_logging(level='INFO'):
    fmt = '%(asctime)s [%(levelname)s] %(name)s: %(message)s'
    logging.basicConfig(level=level, format=fmt)
    return logging.getLogger(__name__)

def validate_port(value):
    port = int(value)
    if not (1 <= port <= 65535):
        raise ValueError(f'Port {port} out of range 1-65535')
    return port

import json
from urllib.request import Request, urlopen
from urllib.error import HTTPError, URLError
def api_get(url, timeout=10):
    req = Request(url, headers={'Accept': 'application/json'})
    try:
        with urlopen(req, timeout=timeout) as resp:
            return json.loads(resp.read())
    except HTTPError as e:
        raise RuntimeError(f'HTTP {e.code}: {e.reason}')

from urllib.parse import parse_qs
def parse_form(body):
    fields = parse_qs(body)
    return {k: v[0] for k, v in fields.items()}

from html.parser import HTMLParser
class LinkParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.links = []
    def handle_starttag(self, tag, attrs):
        if tag == 'a':
            for name, val in attrs:
                if name == 'href':
                    self.links.append(val)

import csv, json
def read_csv(path):
    with open(path, encoding='utf-8') as f:
        return list(csv.DictReader(f))
def read_json(path):
    with open(path, encoding='utf-8') as f:
        return json.load(f)

def validate(data, schema):
    errors = []
    for field, expected_type in schema.items():
        if field not in data:
            errors.append(f'Missing: {field}')
        elif not isinstance(data[field], expected_type):
            errors.append(f'{field}: expected {expected_type.__name__}')
    if errors:
        raise ValueError('; '.join(errors))
    return data

import subprocess
def run_cmd(cmd, timeout=30):
    result = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout)
    if result.returncode != 0:
        raise RuntimeError(f'Command failed: {result.stderr}')
    return result.stdout

import hmac, hashlib, json
def verify_webhook(body, signature, secret):
    expected = hmac.new(secret.encode(), body.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(signature, expected)

import time, random
def retry(fn, max_retries=3, base=2):
    for i in range(max_retries):
        try:
            return fn()
        except Exception:
            if i == max_retries - 1:
                raise
            time.sleep(base ** i + random.uniform(0, 1))

class StateMachine:
    def __init__(self, initial, transitions):
        self.state = initial
        self.transitions = transitions  # {(from, event): to}
    def trigger(self, event):
        key = (self.state, event)
        if key not in self.transitions:
            raise ValueError(f'No transition from {self.state} on {event}')
        self.state = self.transitions[key]

def run_pipeline(stages, initial_data, state_path=None):
    data = initial_data
    for i, stage in enumerate(stages):
        try:
            data = stage(data)
        except Exception as e:
            print(f'Stage {i} failed: {e}')
            raise
    return data

def ask_yes_no(question, default=True):
    suffix = ' [Y/n] ' if default else ' [y/N] '
    while True:
        answer = input(question + suffix).strip().lower()
        if not answer:
            return default
        if answer in ('y', 'yes'):
            return True
        if answer in ('n', 'no'):
            return False
